const imageWidth = $input.first().json.size.width;
const imageHeight = $input.first().json.size.height;

const segmentSize = 950;
const overlap = 50;

// Segment koordinatlarını hesapla
const segments = [];
let currentY = 0;
let segmentIndex = 0;

while (currentY < imageHeight) {
    const remainingHeight = imageHeight - currentY;
    let segmentHeight;

    if (remainingHeight <= segmentSize) {
        segmentHeight = remainingHeight;
    } else if (remainingHeight < segmentSize + overlap) {
        segmentHeight = Math.ceil(remainingHeight / 2);
    } else {
        segmentHeight = segmentSize;
    }

    segments.push({
        index: segmentIndex,
        x: 0,
        y: currentY,
        width: Math.min(segmentSize, imageWidth),
        height: segmentHeight,
        originalWidth: imageWidth,
        originalHeight: imageHeight
    });

    if (remainingHeight <= segmentSize) break;
    currentY += segmentHeight - overlap;
    segmentIndex++;
}

// Her segment için output oluştur
return segments.map(segment => ({
    json: segment,
    binary: $input.first().binary // Original binary data'yı kopyala
}));

