      if (Array.isArray(value)) {
        jsonData = value;
        foundIn = 'data.' + key;
        break;
      } else if (typeof value === 'string') {
        try {
          const parsed = JSON.parse(value);
          if (Array.isArray(parsed)) {
            jsonData = parsed;
            foundIn = 'data.' + key + ' (parsed from string)';
            break;
          }
        } catch (e) {
          console.log(`data.${key} is string but not valid JSON`);
