      console.log(`Found array in ${foundIn} with ${jsonData.length} items`);
      // Her item'ı workflow item'ı olarak döndür
      return jsonData.map((item, index) => ({
        json: {
          url: item.url,
          format: item.format,
          sourceURL: inputData.json.sourceURL || inputData.json.url,
          scrapedAt: new Date().toISOString(),
          itemIndex: index,
          foundIn: foundIn
        }
      }));
    } else {
      // Array bulunamadı - tüm detayları döndür
      return [{
        json: {
