      stack: error.stack
    }
  }];
}

const htmlContent = $input.first().json.data.html;
const MAX_CHUNK_SIZE = 50000;

function splitHtmlContentSafe(content, maxSize) {
  const chunks = [];
  let partIndex = 1;

  // HTML'i DOM parser ile parse et (eğer mümkünse)
  try {
    // Basit HTML tag matcher regex'i
    const htmlTagRegex = /<\/?[^>]+(>|$)/g;
    const tags = [...content.matchAll(htmlTagRegex)];

    // Güvenli bölme noktalarını bul
    const safeSplitPoints = findSafeSplitPoints(content, maxSize);

    let currentPos = 0;

    for (let i = 0; i < safeSplitPoints.length; i++) {
      const splitPoint = safeSplitPoints[i];
      const chunk = content.substring(currentPos, splitPoint);

      chunks.push({
        html_part: chunk,
        part_number: partIndex,
        is_last_part: i === safeSplitPoints.length - 1,
        chunk_size: chunk.length,
        total_original_length: content.length,
        split_at_position: splitPoint,
        split_type: getSplitType(content, splitPoint)
      });

      currentPos = splitPoint;
      partIndex++;
    }

    // Son parçayı işaretle
    if (chunks.length > 0) {
      chunks[chunks.length - 1].total_parts = chunks.length;
    }

    return chunks;

  } catch (error) {
    console.log("HTML parsing hatası, basit bölme kullanılıyor:", error);
    return fallbackSplit(content, maxSize);
  }
}

function findSafeSplitPoints(content, maxSize) {
  const splitPoints = [];
  let currentPos = 0;

  while (currentPos < content.length) {
    let targetPos = Math.min(currentPos + maxSize, content.length);

    if (targetPos >= content.length) {
      splitPoints.push(content.length);
      break;
    }

    // Güvenli bölme noktası ara
    let safeSplitPos = findBestSplitPoint(content, currentPos, targetPos);
    splitPoints.push(safeSplitPos);
    currentPos = safeSplitPos;
  }

  return splitPoints;
}

function findBestSplitPoint(content, start, target) {
  let bestPos = target;

  // Öncelik sırası:
  // 1. Closing tag sonrası (</div>, </p>, vs.)
  // 2. Opening tag öncesi (<div>, <p>, vs.)
  // 3. Satır sonu
  // 4. Boşluk karakteri

  // 1000 karakter geriye git ve en iyi bölme noktasını ara
  const searchStart = Math.max(start, target - 1000);

  // Closing tag sonrası ara
  for (let i = target; i >= searchStart; i--) {
    if (content[i] === '>' && isClosingTag(content, i)) {
      return i + 1;
    }
  }

  // Opening tag öncesi ara
  for (let i = target; i >= searchStart; i--) {
    if (content[i] === '<' && isOpeningTag(content, i)) {
      return i;
    }
  }

  // Satır sonu ara
  for (let i = target; i >= searchStart; i--) {
    if (content[i] === '\n') {
      return i + 1;
    }
  }

  // Boşluk ara
  for (let i = target; i >= searchStart; i--) {
    if (content[i] === ' ') {
      return i + 1;
    }
  }

  return target;
}

function isClosingTag(content, pos) {
  // '>' pozisyonundan geriye git ve '</tag>' yapısını kontrol et
  let i = pos - 1;
  while (i >= 0 && content[i] !== '<') {
    i--;
  }
  return i >= 0 && content[i + 1] === '/';
}

function isOpeningTag(content, pos) {
  // '<' pozisyonundan ileriye git ve '<tag>' yapısını kontrol et
  if (content[pos] !== '<') return false;
  if (pos + 1 < content.length && content[pos + 1] === '/') return false; // Closing tag değil
  if (pos + 1 < content.length && content[pos + 1] === '!') return false; // Comment değil
  return true;
}

function getSplitType(content, pos) {
  if (pos >= content.length) return 'end';
  if (content[pos - 1] === '>') return 'after_closing_tag';
  if (content[pos] === '<') return 'before_opening_tag';
  if (content[pos] === '\n') return 'line_break';
  if (content[pos] === ' ') return 'whitespace';
  return 'character';
}

function fallbackSplit(content, maxSize) {
  // Basit fallback - sadece kelime sınırlarında böl
  const chunks = [];
  let currentPos = 0;
  let partIndex = 1;

  while (currentPos < content.length) {
    let endPos = Math.min(currentPos + maxSize, content.length);

    if (endPos < content.length) {
      // Kelime sınırı ara
      while (endPos > currentPos && 
             content[endPos] !== ' ' && 
             content[endPos] !== '\n' && 
             content[endPos] !== '\t') {
        endPos--;
      }

      if (endPos === currentPos) {
        endPos = Math.min(currentPos + maxSize, content.length);
      }
    }

    const chunk = content.substring(currentPos, endPos);
    chunks.push({
      html_part: chunk,
      part_number: partIndex,
      is_last_part: endPos >= content.length,
      chunk_size: chunk.length,
      total_original_length: content.length,
      split_type: 'fallback'
    });

    currentPos = endPos;
    partIndex++;
  }

  if (chunks.length > 0) {
    chunks[chunks.length - 1].total_parts = chunks.length;
  }

  return chunks;
}

// Alternatif: Semantic bölme (belirli HTML elementlerine göre)
function splitByElements(content, maxSize) {
  const chunks = [];
  let partIndex = 1;

  // Ana HTML bloklarını bul (div, section, article, vs.)
  const blockElements = ['div', 'section', 'article', 'main', 'header', 'footer', 'nav'];
  const blockRegex = new RegExp(`<(${blockElements.join('|')})[^>]*>`, 'gi');

  let matches = [...content.matchAll(blockRegex)];
  matches.push({ index: content.length }); // Son eleman

  let currentPos = 0;
  let currentChunk = '';

  for (let i = 0; i < matches.length; i++) {
    const nextBlockStart = matches[i].index;
    const segmentContent = content.substring(currentPos, nextBlockStart);

    if (currentChunk.length + segmentContent.length <= maxSize) {
      currentChunk += segmentContent;
    } else {
      if (currentChunk.length > 0) {
        chunks.push({
          html_part: currentChunk,
          part_number: partIndex,
          is_last_part: false,
          chunk_size: currentChunk.length,
          total_original_length: content.length,
          split_type: 'semantic_block'
        });
        partIndex++;
      }
      currentChunk = segmentContent;
    }

    currentPos = nextBlockStart;
  }

  // Son parçayı ekle
  if (currentChunk.length > 0) {
    chunks.push({
      html_part: currentChunk,
      part_number: partIndex,
      is_last_part: true,
      chunk_size: currentChunk.length,
      total_original_length: content.length,
      total_parts: partIndex,
      split_type: 'semantic_block'
    });
  }

  return chunks;
}

// Ana fonksiyon - HTML içeriğini güvenli şekilde böl
const htmlChunks = splitHtmlContentSafe(htmlContent, MAX_CHUNK_SIZE);


// Sonuçları döndür
return htmlChunks.map(chunk => ({ json: chunk }));

// n8n Code Node (Node.js) — async IIFE ile güvenli yürütme
return await (async () => {
  // 0) Yardımcı: Python list[str->dict] çıktısını sağlam JSON'a çevir - DÜZELTİLMİŞ
  function parsePythonListString(s) {
    if (typeof s !== 'string') throw new Error('parsePythonListString input is not string');
    let cleaned = s.trim();

    // Olası code-block işaretlerini temizle
    cleaned = cleaned.replace(/^```(?:json|python)?\s*/i, '').replace(/```$/i, '');

    // Python -> JSON dönüşümleri
    cleaned = cleaned
      .replace(/\bNone\b/g, 'null')
      .replace(/\bTrue\b/g, 'true')
      .replace(/\bFalse\b/g, 'false');

    // DÜZELTİLMİŞ: Önce escape edilmiş tırnakları geçici placeholder ile koru
    const ESCAPED_QUOTE_PLACEHOLDER = '__ESCAPED_QUOTE__';
    cleaned = cleaned.replace(/\\"/g, ESCAPED_QUOTE_PLACEHOLDER);

    // Sonra tek tırnakları çift tırnağa çevir
    cleaned = cleaned.replace(/'/g, '"');

    // Placeholder'ları geri escape edilmiş çift tırnak yap
    cleaned = cleaned.replace(new RegExp(ESCAPED_QUOTE_PLACEHOLDER, 'g'), '\\"');

    // İçindeki çift tırnakları escape et - string değerleri içindeki çift tırnaklar için
    // Bu daha karmaşık bir regex ile yapılmalı, basit yaklaşım:
    // "title": "some "quoted" text" -> "title": "some \"quoted\" text"
    cleaned = cleaned.replace(/":\s*"([^"]*)"([^"]*)"([^"]*?)"/g, '": "$1\\"$2\\"$3"');

    // Fazla virgül / satır sonları gibi minör temizlikler
    cleaned = cleaned.replace(/\n+/g, ' ').replace(/,\s*]/g, ']').replace(/,\s*}/g, '}');

    // Son olarak JSON.parse dene
    return JSON.parse(cleaned);
  }

  // GELİŞTİRİLMİŞ Python dict string parser
  function parseAdvancedPythonDict(s) {
    if (typeof s !== 'string') throw new Error('Input is not string');

    let cleaned = s.trim();

    // Code block işaretlerini temizle
    cleaned = cleaned.replace(/^```(?:json|python)?\s*/i, '').replace(/```$/i, '');

    // Python özel değerleri
    cleaned = cleaned
      .replace(/\bNone\b/g, 'null')
      .replace(/\bTrue\b/g, 'true')
      .replace(/\bFalse\b/g, 'false');

    // GELİŞTİRİLMİŞ Manual parsing yaklaşımı
    try {
      const items = [];

      // Tüm dict'leri bul - daha esnek regex
      // Hem tek hem çift tırnak kombinasyonlarını yakalar
      const dictPattern = /\{\s*['"]title['"]\s*:\s*(['"])((?:(?!\1)[^\\]|\\.)*)?\1\s*,\s*['"]link['"]\s*:\s*(['"])((?:(?!\3)[^\\]|\\.)*)?\3\s*\}/g;

      let match;
      while ((match = dictPattern.exec(cleaned)) !== null) {
        const title = match[2] || '';
        const link = match[4] || '';

        items.push({
          title: title.replace(/\\"/g, '"').replace(/\\'/g, "'"), // Escape edilmiş tırnakları düzelt
          link: link.replace(/\\"/g, '"').replace(/\\'/g, "'")
        });
      }

      if (items.length > 0) {
        return items;
      }

      // Alternatif yaklaşım: Daha basit regex'ler
      const simplePatterns = [
        // Pattern 1: Her ikisi de tek tırnak
        /\{\s*'title'\s*:\s*'([^']+)'\s*,\s*'link'\s*:\s*'([^']+)'\s*\}/g,
        // Pattern 2: Her ikisi de çift tırnak  
        /\{\s*"title"\s*:\s*"([^"]+)"\s*,\s*"link"\s*:\s*"([^"]+)"\s*\}/g,
        // Pattern 3: Title çift, link tek
        /\{\s*'title'\s*:\s*"([^"]+)"\s*,\s*'link'\s*:\s*'([^']+)'\s*\}/g,
        // Pattern 4: Title tek, link çift
        /\{\s*'title'\s*:\s*'([^']+)'\s*,\s*'link'\s*:\s*"([^"]+)"\s*\}/g,
      ];

      for (let i = 0; i < simplePatterns.length; i++) {
        const pattern = simplePatterns[i];

        // Reset regex
        pattern.lastIndex = 0;

        while ((match = pattern.exec(cleaned)) !== null) {
          const title = match[1] || '';
          const link = match[2] || '';

          items.push({
            title: title,
            link: link
          });
        }

        if (items.length > 0) {
          break;
        }
      }

      if (items.length > 0) {
        return items;
      }

      // Son çare: Manuel string splitting

      // Array bracket'larını temizle
      let arrayContent = cleaned.replace(/^\[|\]$/g, '').trim();

      // Dict'leri split et - basit yaklaşım
      const dictStrings = [];
      let braceCount = 0;
      let currentDict = '';

      for (let i = 0; i < arrayContent.length; i++) {
        const char = arrayContent[i];
        currentDict += char;

        if (char === '{') braceCount++;
        else if (char === '}') {
          braceCount--;
          if (braceCount === 0) {
            dictStrings.push(currentDict.trim());
            currentDict = '';
          }
        }
      }

      for (const dictStr of dictStrings) {
        // Her dict string'ini ayrı ayrı parse et
        const titleMatch = dictStr.match(/['"]title['"]:\s*['"]([^'"]+)['"]/);
        const linkMatch = dictStr.match(/['"]link['"]:\s*['"]([^'"]+)['"]/);

        if (titleMatch && linkMatch) {
          items.push({
            title: titleMatch[1],
            link: linkMatch[1]
          });
        }
      }

      if (items.length > 0) {
        return items;
      }

      // Son çare: standart JSON parse
      const standardCleaned = cleaned.replace(/'/g, '"');
      return JSON.parse(standardCleaned);

    } catch (e) {
      throw new Error(`Could not parse Python dict string: ${e.message}`);
    }
  }

  // 1) Girdi - TÜM STDOUT'LARI BİRLEŞTİR

  let allStdoutData = [];
  let inputData = null;

  // Tüm input'ları kontrol et ve stdout verilerini topla
  const allInputs = $input.all();
  for (let i = 0; i < allInputs.length; i++) {
    const currentInput = allInputs[i];

    // stdout alanını kontrol et ve biriktir
    if (currentInput.json && currentInput.json.stdout && currentInput.json.stdout.trim() !== '') {
      allStdoutData.push(currentInput.json.stdout);
    }

    // Doğrudan json alanını kontrol et (array ise)
    if (currentInput.json && Array.isArray(currentInput.json)) {
      if (!inputData) inputData = currentInput.json;
    }
  }

  // Eğer hiçbir veri bulunamazsa error döndür
  if (allStdoutData.length === 0 && !inputData) {
    return [{
      json: {
        error: 'Beklenmeyen format',
        data: 'No stdout data found',
        inputType: 'object',
        message: 'Hiçbir stdout verisi bulunamadı. Python kodunun çıktı ürettiğinden emin olun.',
        exitCode: 0,
        stderr: '[empty]',
        stdout: '[empty]',
        debug: {
          totalInputs: allInputs.length,
          inputStructure: allInputs.map((inp, idx) => ({
            index: idx,
            hasJson: !!inp.json,
            jsonType: inp.json ? typeof inp.json : null,
            hasStdout: !!(inp.json && inp.json.stdout),
            stdoutLength: inp.json && inp.json.stdout ? inp.json.stdout.length : 0
          }))
        }
      }
    }];
  }

  // Eğer stdout verileri varsa, bunları birleştir
  if (allStdoutData.length > 0) {
    // Her stdout'u ayrı ayrı parse et ve birleştir
    let combinedArray = [];
    for (let i = 0; i < allStdoutData.length; i++) {
      try {
        const stdoutData = allStdoutData[i];
        const parsedData = parseAdvancedPythonDict(stdoutData);
        if (Array.isArray(parsedData)) {
          combinedArray = combinedArray.concat(parsedData);
        }
      } catch (e) {
        // Parse hatası durumunda ham veriyi de göster
        return [{
          json: {
            error: 'JSON parse hatası',
            message: e.message,
            hint: 'Python dictionary formatı düzgün parse edilemedi. Çift tırnak içindeki çift tırnaklar escape edilmeli.',
            failedStdout: allStdoutData[i].substring(0, 500),
            stdoutIndex: i,
            totalStdoutCount: allStdoutData.length,
            suggestion: 'Python kodunda title değerlerindeki çift tırnakları escape edin veya tek tırnak kullanın.'
          }
        }];
      }
    }
    inputData = combinedArray;
  }

  // Eğer hiçbirinde veri bulunamazsa, ilk input'u al
  if (!inputData) {
    inputData = $input.first().json;
  }

  // 2) Python dictionary listesini parse et
  let dataArray;
  try {
    if (typeof inputData === 'string') {
      dataArray = parseAdvancedPythonDict(inputData);
    } else if (Array.isArray(inputData)) {
      dataArray = inputData;
    } else {
      return [{
        json: {
          error: 'Beklenmeyen format',
          data: inputData,
          inputType: typeof inputData,
          exitCode: 0,
          stderr: '[empty]',
          stdout: '[empty]',
          message: 'Input data array değil ve string de değil. Python kodunun list[dict] formatında çıktı ürettiğinden emin olun.'
        }
      }];
    }
  } catch (e) {
    // Sorunu görünür kılmak için ilk 300 karakteri geri döndür
    return [{
      json: {
        error: 'JSON parse hatası',
        message: e.message,
        hint: 'Python dictionary formatı parse edilemedi. Title içindeki çift tırnaklar sorun yaratmış olabilir.',
        sample: typeof inputData === 'string' ? inputData.slice(0, 300) : String(inputData),
        totalStdoutCount: allStdoutData.length,
        fullInput: inputData,
        suggestion: 'Python kodunda json.dumps() kullanarak düzgün JSON çıktısı üretin.'
      }
    }];
  }

  // Array kontrolü
  if (!Array.isArray(dataArray)) {
    return [{
      json: {
        error: 'Parse edilmiş veri array değil',
        dataType: typeof dataArray,
        data: dataArray,
        totalStdoutProcessed: allStdoutData.length,
        message: 'Parse sonucu array olmadı. Python kodunuz list döndürüyor mu?'
      }
    }];
  }

  // Boş array kontrolü
  if (dataArray.length === 0) {
    return [{
      json: {
        error: 'Beklenmeyen format',
        data: 'Empty array',
        inputType: 'array',
        exitCode: 0,
        stderr: '[empty]',
        stdout: '[empty]',
        message: 'Parse edilen array boş. Python kodunuz veri döndürüyor mu?'
      }
    }];
  }

  // 3) Link analiz fonksiyonu - DÜZELTİLMİŞ VERSİYON (aynı)
  async function classifyLink(link) {
    try {

      // URL'i parse et - n8n ortamında URL constructor olmayabilir, manuel parsing yapalım
      let url, pathname, queryParams, hostname;

      try {
        // Önce standart URL constructor'ı dene
        url = new URL(link);
        pathname = url.pathname.toLowerCase();
        queryParams = (url.search || '').toLowerCase();
        hostname = url.hostname;
      } catch (urlError) {
        // Manuel URL parsing
        const linkLower = link.toLowerCase();
        const protocolIndex = linkLower.indexOf('://');
        if (protocolIndex === -1) {
          pathname = link.toLowerCase();
          queryParams = '';
          hostname = '';
        } else {
          const afterProtocol = link.substring(protocolIndex + 3);
          const pathIndex = afterProtocol.indexOf('/');
          if (pathIndex === -1) {
            hostname = afterProtocol.toLowerCase();
            pathname = '/';
            queryParams = '';
          } else {
            hostname = afterProtocol.substring(0, pathIndex).toLowerCase();
            const pathAndQuery = afterProtocol.substring(pathIndex);
            const queryIndex = pathAndQuery.indexOf('?');
            if (queryIndex === -1) {
              pathname = pathAndQuery.toLowerCase();
              queryParams = '';
            } else {
              pathname = pathAndQuery.substring(0, queryIndex).toLowerCase();
              queryParams = pathAndQuery.substring(queryIndex).toLowerCase();
            }
          }
        }
      }

      const fullUrl = link.toLowerCase(); // Tüm URL'i küçük harfe çevir

      // 3.1 Uzantı analizi - DÜZELTİLMİŞ
      const documentExtensions = ['.pdf', '.doc', '.docx', '.rtf', '.odt'];
      const otherExtensions = ['.zip', '.rar', '.7z', '.tar', '.gz', '.xlsx', '.xls', '.csv', '.ppt', '.pptx', '.txt', '.xml', '.json'];

      // Önce tam URL'de uzantı ara (query parametrelerinden önce)
      for (const ext of documentExtensions) {
        if (fullUrl.includes(ext)) {
          return { format: 'document', confidence: 'high', method: 'extension', extension: ext };
        }
      }

      for (const ext of otherExtensions) {
        if (fullUrl.includes(ext)) {
          return { format: 'other', confidence: 'high', method: 'extension', extension: ext };
        }
      }

      // Ayrıca pathname'de de kontrol et
      for (const ext of documentExtensions) {
        if (pathname.endsWith(ext)) {
          return { format: 'document', confidence: 'high', method: 'extension', extension: ext };
        }
      }

      for (const ext of otherExtensions) {
        if (pathname.endsWith(ext)) {
          return { format: 'other', confidence: 'high', method: 'extension', extension: ext };
        }
      }

      // 3.2 Pattern analizi - GELİŞTİRİLMİŞ
      const documentPatterns = [
        /\/download.*\.(pdf|doc|docx)\b/i,
        /\/files?\/.*\.(pdf|doc|docx)\b/i,
        /\/documents?\/.*\.(pdf|doc|docx)\b/i,
        /\/(pdf|doc|document)\b/i,
        /[?&](file|download)=.*\.(pdf|doc|docx)\b/i,
        /\.(pdf|doc|docx)($|[?&#])/i, // URL sonunda veya query/fragment başlangıcında
      ];

      const otherPatterns = [
        /\/download.*\.(zip|xlsx?|csv|pptx?)\b/i,
        /\/export\b/i,
        /\/api\/.*\/(export|download)\b/i,
        /[?&](format|type)=(excel|csv|zip)\b/i,
        /[?&](export|download)=/i,
        /\.(zip|xlsx?|csv|pptx?)($|[?&#])/i,
      ];

      const fullUrlForPattern = pathname + queryParams;

      for (const p of documentPatterns) {
        if (p.test(fullUrlForPattern)) {
          return { format: 'document', confidence: 'medium', method: 'pattern' };
        }
      }

      for (const p of otherPatterns) {
        if (p.test(fullUrlForPattern)) {
          return { format: 'other', confidence: 'medium', method: 'pattern' };
        }
      }

      // 3.3 Domain kuralları
      const documentDomains = ['docs.', 'documents.', 'papers.', 'files.'];
      const downloadDomains = ['download.', 'cdn.', 'assets.', 'static.'];
      if (documentDomains.some(d => hostname.includes(d))) {
        return { format: 'document', confidence: 'low', method: 'domain' };
      }
      if (downloadDomains.some(d => hostname.includes(d))) {
        return { format: 'other', confidence: 'low', method: 'domain' };
      }

      // 3.4 HEAD isteği (AbortController ile timeout)
      try {
        const controller = new AbortController();
        const id = setTimeout(() => controller.abort(), 5000);

        const response = await fetch(link, {
          method: 'HEAD',
          headers: { 'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36' },
          signal: controller.signal,
        });
        clearTimeout(id);

        const contentType = response.headers.get('content-type') || '';
        const contentDisposition = response.headers.get('content-disposition') || '';

        const isDocCT =
          contentType.includes('application/pdf') ||
          contentType.includes('application/msword') ||
          contentType.includes('application/vnd.openxmlformats-officedocument.wordprocessingml');
        const isDocCD = /attachment/i.test(contentDisposition) && /\.(pdf|doc|docx)\b/i.test(contentDisposition);

        if (isDocCT || isDocCD) {
          return { format: 'document', confidence: 'very-high', method: 'content-type', contentType };
        }

        const isOtherCT =
          contentType.includes('application/zip') ||
          contentType.includes('application/vnd.ms-excel') ||
          contentType.includes('application/vnd.openxmlformats-officedocument.spreadsheetml') ||
          contentType.includes('application/octet-stream') ||
          contentType.includes('application/x-download');
        const isOtherCD = /attachment/i.test(contentDisposition);
        if (isOtherCT || isOtherCD) {
          return { format: 'other', confidence: 'very-high', method: 'content-type', contentType };
        }

        if (contentType.includes('text/html') || contentType.includes('text/plain')) {
          return { format: 'page', confidence: 'very-high', method: 'content-type', contentType };
        }
      } catch (headErr) {
        // HEAD başarısızsa devam
      }

      // 3.5 Web sayfası heuristikleri
      const webPatterns = ['/news/', '/article/', '/blog/', '/post/', '/page/', '/about/', '/contact/'];
      if (webPatterns.some(p => pathname.includes(p))) {
        return { format: 'page', confidence: 'medium', method: 'web-pattern' };
      }

      return { format: 'page', confidence: 'low', method: 'default' };
    } catch (e) {
      return { format: 'page', confidence: 'error', method: 'fallback', error: e.message };
    }
  }

  // 4) Her dictionary'yi işle - DUPLICATE DETECTION EKLENDI
  const results = [];
  const processedLinks = new Set();

  for (let i = 0; i < dataArray.length; i++) {
    const item = dataArray[i];

    if (item && typeof item === 'object' && item.title && item.link) {
      // Link kontrolü - aynı link varsa atla
      if (processedLinks.has(item.link)) {
        continue;
      }

      processedLinks.add(item.link);

      const classification = await classifyLink(item.link);
      results.push({
        json: {
          title: item.title,
          link: item.link,
          format: classification.format,
          confidence: classification.confidence,
          detectionMethod: classification.method,
          metadata: {
            extension: classification.extension || null,
            contentType: classification.contentType || null,
            error: classification.error || null,
          },
        },
      });
    } else {
      results.push({
        json: {
          title: 'Invalid Format',
          link: 'N/A',
          format: 'error',
          confidence: 'error',
          detectionMethod: 'validation',
          metadata: {
            error: 'Invalid dictionary format - missing title or link',
            originalData: item,
          },
        },
      });
    }
  }

  return results;
})();

